  1	import * as React from 'react';
  2	import { AttachStorageAction } from '@odf/core/components/attach-storage-storagesystem/state';
  3	import { checkArbiterCluster } from '@odf/core/utils';
  4	import {
  5	  fieldRequirementsTranslations,
  6	  formSettings,
  7	} from '@odf/shared/constants';
  8	import { useK8sGet } from '@odf/shared/hooks';
  9	import { TextInputWithFieldRequirements } from '@odf/shared/input-with-requirements';
 10	import { StorageClusterModel } from '@odf/shared/models';
 11	import { getNamespace } from '@odf/shared/selectors';
 12	import {
 13	  ListKind,
 14	  StorageClusterKind,
 15	  CephClusterKind,
 16	} from '@odf/shared/types';
 17	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 18	import validationRegEx from '@odf/shared/utils/validation';
 19	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 20	import * as _ from 'lodash-es';
 21	import { useForm } from 'react-hook-form';
 22	import * as Yup from 'yup';
 23	import {
 24	  Alert,
 25	  EmptyState,
 26	  EmptyStateIcon,
 27	  EmptyStateBody,
 28	  EmptyStateHeader,
 29	  Radio,
 30	  FormGroup,
 31	  TextInput,
 32	  Icon,
 33	  Dropdown,
 34	  DropdownItem,
 35	  DropdownList,
 36	  MenuToggle,
 37	  MenuToggleElement,
 38	} from '@patternfly/react-core';
 39	import { CaretDownIcon, InfoCircleIcon } from '@patternfly/react-icons';
 40	import {
 41	  OCS_DEVICE_REPLICA,
 42	  PoolProgress,
 43	  PoolState,
 44	  PoolType,
 45	} from '../constants';
 46	import {
 47	  getErrorMessage,
 48	  ProgressStatusProps,
 49	  PROGRESS_STATUS,
 50	} from '../utils';
 51	import {
 52	  StoragePoolAction,
 53	  StoragePoolActionType,
 54	  StoragePoolState,
 55	} from './reducer';
 56	import '../style.scss';
 57	import './body.scss';
 58	
 59	export const StoragePoolStatus: React.FC<StoragePoolStatusProps> = ({
 60	  status,
 61	  name,
 62	  error = '',
 63	}) => {
 64	  const { t } = useCustomTranslation();
 65	  const statusObj: ProgressStatusProps = PROGRESS_STATUS(t, name).find(
 66	    (state) => state.name === status
 67	  );
 68	
 69	  return (
 70	    <EmptyState>
 71	      <EmptyStateHeader
 72	        icon={
 73	          <EmptyStateIcon
 74	            icon={statusObj.icon}
 75	            className={statusObj.className}
 76	          />
 77	        }
 78	      />
 79	      <EmptyStateBody data-test="empty-state-body">
 80	        {error ? getErrorMessage(error) : statusObj.desc}
 81	      </EmptyStateBody>
 82	    </EmptyState>
 83	  );
 84	};
 85	
 86	export type StoragePoolStatusProps = {
 87	  status: string;
 88	  name?: string;
 89	  error?: string;
 90	};
 91	
 92	export type StoragePoolBodyProps = {
 93	  cephCluster: CephClusterKind;
 94	  state: StoragePoolState;
 95	  showPoolStatus: boolean;
 96	  dispatch: React.Dispatch<StoragePoolAction | AttachStorageAction>;
 97	  poolType: PoolType;
 98	  existingNames?: string[];
 99	  onPoolTypeChange?: (newPoolType: PoolType) => void;
100	  disablePoolType?: boolean;
101	  isUpdate?: boolean;
102	  prefixName?: string;
103	  usePrefix?: boolean;
104	  placeholder?: string;
105	};
106	
107	export const StoragePoolBody: React.FC<StoragePoolBodyProps> = ({
108	  cephCluster,
109	  state,
110	  showPoolStatus,
111	  dispatch,
112	  poolType,
113	  existingNames,
114	  onPoolTypeChange,
115	  disablePoolType,
116	  isUpdate,
117	  prefixName,
118	  usePrefix,
119	  placeholder,
120	}) => {
121	  const { t } = useCustomTranslation();
122	
123	  const poolNs = getNamespace(cephCluster);
124	
125	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
126	    useK8sGet<ListKind<StorageClusterKind>>(StorageClusterModel, null, poolNs);
127	
128	  const [isReplicaOpen, setReplicaOpen] = React.useState(false);
129	
130	  const poolNameMaxLength = 253;
131	  const { schema, fieldRequirements } = React.useMemo(() => {
132	    const translationFieldRequirements = [
133	      fieldRequirementsTranslations.maxChars(t, poolNameMaxLength),
134	      fieldRequirementsTranslations.startAndEndName(t),
135	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
136	      fieldRequirementsTranslations.cannotBeUsedBefore(t),
137	    ];
138	
139	    const validationSchema = Yup.object({
140	      newPoolName: Yup.string()
141	        .required()
142	        .max(poolNameMaxLength, translationFieldRequirements[0])
143	        .matches(
144	          validationRegEx.startAndEndsWithAlphanumerics,
145	          translationFieldRequirements[1]
146	        )
147	        .matches(
148	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
149	          translationFieldRequirements[2]
150	        )
151	        .test(
152	          'unique-name',
153	          translationFieldRequirements[3],
154	          (value: string) =>
155	            !existingNames.includes(
156	              usePrefix ? `${prefixName}-${value}` : value
157	            )
158	        ),
159	    });
160	
161	    return {
162	      schema: validationSchema,
163	      fieldRequirements: translationFieldRequirements,
164	    };
165	  }, [prefixName, usePrefix, existingNames, t]);
166	
167	  const resolver = useYupValidationResolver(schema);
168	  const {
169	    formState: { errors },
170	    control,
171	    watch,
172	  } = useForm({
173	    ...formSettings,
174	    resolver,
175	  });
176	
177	  const poolName: string = watch('newPoolName');
178	
179	  React.useEffect(() => {
180	    // Update pool name: set empty on validation error.
181	    const possiblyPrefixedPoolName =
182	      usePrefix && poolName ? `${prefixName}-${poolName}` : poolName;
183	    const payload = errors?.newPoolName ? '' : possiblyPrefixedPoolName;
184	    dispatch({
185	      type: StoragePoolActionType.SET_POOL_NAME,
186	      payload: payload,
187	    });
188	  }, [poolName, dispatch, errors?.newPoolName, prefixName, usePrefix]);
189	
190	  // Failure Domain
191	  React.useEffect(() => {
192	    if (storageClusterLoaded && !storageClusterLoadError)
193	      dispatch({
194	        type: StoragePoolActionType.SET_FAILURE_DOMAIN,
195	        payload: storageCluster?.items[0]?.status?.failureDomain || '',
196	      });
197	  }, [storageCluster, storageClusterLoaded, storageClusterLoadError, dispatch]);
198	
199	  // Check storage cluster is in ready state
200	  const isClusterReady: boolean =
201	    cephCluster?.status?.phase === PoolState.READY;
202	
203	  // Check storage cluster is arbiter
204	  React.useEffect(() => {
205	    const isArbiterCluster: boolean = checkArbiterCluster(
206	      storageCluster?.items[0]
207	    );
208	    dispatch({
209	      type: StoragePoolActionType.SET_POOL_ARBITER,
210	      payload: isArbiterCluster,
211	    });
212	    if (isArbiterCluster) {
213	      dispatch({
214	        type: StoragePoolActionType.SET_POOL_REPLICA_SIZE,
215	        payload: '4',
216	      });
217	    }
218	  }, [
219	    storageCluster,
220	    storageClusterLoaded,
221	    storageClusterLoadError,
222	    state.isArbiterCluster,
223	    dispatch,
224	  ]);
225	
226	  const replicaList: string[] = _.keys(OCS_DEVICE_REPLICA).filter(
227	    (replica: string) =>
228	      (state.isArbiterCluster && replica === '4') ||
229	      (!state.isArbiterCluster && replica !== '4')
230	  );
231	
232	  const replicaDropdownItems = replicaList.map((replica) => {
233	    let warning = '';
234	    if (replica === '2') {
235	      warning = t(
236	        'Data loss may occur, only recommended for small clusters or when backups are available or data loss is acceptable'
237	      );
238	    }
239	    return (
240	      <DropdownItem
241	        key={`replica-${OCS_DEVICE_REPLICA[replica]}`}
242	        component="button"
243	        id={replica}
244	        data-test-id="replica-dropdown-item"
245	        className="ceph-block-pool__dropdown-description"
246	        description={warning}
247	        onClick={(e) =>
248	          dispatch({
249	            type: StoragePoolActionType.SET_POOL_REPLICA_SIZE,
250	            payload: e.currentTarget.id,
251	          })
252	        }
253	      >
254	        {t('{{replica}} Replication', {
255	          replica: OCS_DEVICE_REPLICA[replica],
256	        })}
257	      </DropdownItem>
258	    );
259	  });
260	
261	  const replicaDropdownToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
262	    <MenuToggle
263	      ref={toggleRef}
264	      id="replica-dropdown"
265	      data-test="replica-dropdown"
266	      onClick={() => setReplicaOpen(!isReplicaOpen)}
267	      isExpanded={isReplicaOpen}
268	      icon={<CaretDownIcon />}
269	      isDisabled={state.isArbiterCluster}
270	      isFullWidth
271	    >
272	      {state.replicaSize
273	        ? t('{{replica}} Replication', {
274	            replica: OCS_DEVICE_REPLICA[state.replicaSize],
275	          })
276	        : t('Select replication')}
277	    </MenuToggle>
278	  );
279	
280	  return isClusterReady || !showPoolStatus ? (
281	    <>
282	      <FormGroup label={t('Volume type')} className="pf-v6-u-pt-xl" isRequired>
283	        <div className="pf-v6-u-display-flex pf-v6-u-flex-direction-row ceph-pool__radio-flex">
284	          <Radio
285	            label={t('Filesystem')}
286	            value="filesystem"
287	            id="type-filesystem"
288	            data-test="type-filesystem"
289	            name="volume-type"
290	            className="pf-v6-u-mr-4xl"
291	            isChecked={poolType === PoolType.FILESYSTEM}
292	            isDisabled={disablePoolType && poolType !== PoolType.FILESYSTEM}
293	            onChange={() => {
294	              onPoolTypeChange(PoolType.FILESYSTEM);
295	            }}
296	          />
297	          <Radio
298	            label={t('Block')}
299	            value="block"
300	            id="type-block"
301	            data-test="type-block"
302	            name="volume-type"
303	            isChecked={poolType === PoolType.BLOCK}
304	            isDisabled={disablePoolType && poolType !== PoolType.BLOCK}
305	            onChange={() => {
306	              onPoolTypeChange(PoolType.BLOCK);
307	            }}
308	          />
309	        </div>
310	      </FormGroup>
311	      <TextInputWithFieldRequirements
312	        control={control}
313	        fieldRequirements={fieldRequirements}
314	        defaultValue={state.poolName}
315	        popoverProps={{
316	          headerContent: t('Name requirements'),
317	          footerContent: `${t('Example')}: my-pool`,
318	        }}
319	        formGroupProps={{
320	          label: t('Pool name'),
321	          fieldId: 'pool-name',
322	          className: 'ceph-block-pool-body__input',
323	          isRequired: true,
324	        }}
325	        textInputProps={{
326	          id: 'pool-name',
327	          name: 'newPoolName',
328	          'data-test': 'new-pool-name-textbox',
329	          'aria-describedby': t('pool-name-help'),
330	          placeholder: placeholder || t('my-pool'),
331	          isDisabled: isUpdate,
332	        }}
333	        infoElement={
334	          (usePrefix || poolType === PoolType.FILESYSTEM) && (
335	            <>
336	              <Icon status="info">
337	                <InfoCircleIcon />
338	              </Icon>
339	              <span className="pf-v5-u-disabled-color-100 pf-v6-u-font-size-sm pf-v6-u-ml-sm">
340	                {t(
341	                  'The pool name comprises a prefix followed by the user-provided name.'
342	                )}
343	              </span>
344	            </>
345	          )
346	        }
347	        inputPrefixElement={
348	          (usePrefix || poolType === PoolType.FILESYSTEM) && (
349	            <>
350	              <TextInput
351	                id="pool-prefix"
352	                className="pool-prefix"
353	                value={prefixName}
354	                isDisabled={true}
355	              />
356	              <div className="pf-v6-u-ml-sm pf-v6-u-mr-sm">-</div>
357	            </>
358	          )
359	        }
360	      />
361	      <div className="form-group ceph-block-pool-body__input">
362	        <label
363	          className="control-label co-required"
364	          htmlFor="pool-replica-size"
365	        >
366	          {t('Data protection policy')}
367	        </label>
368	        <Dropdown
369	          className="dropdown--full-width"
370	          isOpen={isReplicaOpen}
371	          onSelect={() => setReplicaOpen(false)}
372	          onOpenChange={(open: boolean) => setReplicaOpen(open)}
373	          toggle={replicaDropdownToggle}
374	          popperProps={{ width: 'trigger' }}
375	        >
376	          <DropdownList>{replicaDropdownItems}</DropdownList>
377	        </Dropdown>
378	      </div>
379	      <div className="form-group ceph-block-pool-body__input">
380	        <label className="control-label" htmlFor="compression-check">
381	          {t('Data compression')}
382	        </label>
383	        <div className="checkbox ceph-block-pool-body__compression">
384	          <input
385	            type="checkbox"
386	            onChange={(event) =>
387	              dispatch({
388	                type: StoragePoolActionType.SET_POOL_COMPRESSED,
389	                payload: event.target.checked,
390	              })
391	            }
392	            checked={state.isCompressed}
393	            id="compression-check"
394	            name="compression-check"
395	            data-test="compression-checkbox"
396	          />
397	          {t(
398	            'Optimize storage efficiency by enabling data compression within replicas.'
399	          )}
400	        </div>
401	      </div>
402	      {state.isCompressed && (
403	        <Alert
404	          className="co-alert ceph-block-pool__alert"
405	          variant="info"
406	          title={t(
407	            'Enabling compression may result in little or no space savings for encrypted or random data. Also, enabling compression may have an impact on I/O performance.'
408	          )}
409	          isInline
410	        />
411	      )}
412	    </>
413	  ) : (
414	    <StoragePoolStatus status={PoolProgress.CLUSTERNOTREADY} />
415	  );
416	};

