124	
125	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
126	    useK8sGet<ListKind<StorageClusterKind>>(StorageClusterModel, null, poolNs);
127	
128	  const [isReplicaOpen, setReplicaOpen] = React.useState(false);
129	
130	  const poolNameMaxLength = 253;
131	  const { schema, fieldRequirements } = React.useMemo(() => {
132	    const translationFieldRequirements = [
133	      fieldRequirementsTranslations.maxChars(t, poolNameMaxLength),
134	      fieldRequirementsTranslations.startAndEndName(t),
135	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
