 17	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 18	import validationRegEx from '@odf/shared/utils/validation';
 19	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 20	import * as _ from 'lodash-es';
 21	import { useForm } from 'react-hook-form';
 22	import * as Yup from 'yup';
 23	import {
 24	  Alert,
 25	  EmptyState,
 26	  EmptyStateBody,
 27	  Radio,
 28	  FormGroup,
 29	  TextInput,
 30	  Icon,
 31	  Dropdown,
 32	  DropdownItem,
 33	  DropdownList,
 34	  MenuToggle,
 35	  MenuToggleElement,
 36	} from '@patternfly/react-core';
 37	import { CaretDownIcon, InfoCircleIcon } from '@patternfly/react-icons';
 38	import {
 39	  OCS_DEVICE_REPLICA,
 40	  PoolProgress,
 41	  PoolState,
 42	  PoolType,
 43	} from '../constants';
 44	import {
 45	  getErrorMessage,
 46	  ProgressStatusProps,
 47	  PROGRESS_STATUS,
 48	} from '../utils';
 49	import {
 50	  StoragePoolAction,
 51	  StoragePoolActionType,
 52	  StoragePoolState,
 53	} from './reducer';
 54	import '../style.scss';
 55	import './body.scss';
 56	
 57	export const StoragePoolStatus: React.FC<StoragePoolStatusProps> = ({
 58	  status,
 59	  name,
 60	  error = '',
 61	}) => {
 62	  const { t } = useCustomTranslation();
 63	  const statusObj: ProgressStatusProps = PROGRESS_STATUS(t, name).find(
 64	    (state) => state.name === status
 65	  );
 66	
 67	  return (
 68	    <EmptyState icon={statusObj.icon}>
 69	      <EmptyStateBody data-test="empty-state-body">
 70	        {error ? getErrorMessage(error) : statusObj.desc}
 71	      </EmptyStateBody>
 72	    </EmptyState>
 73	  );
 74	};
 75	
 76	export type StoragePoolStatusProps = {
 77	  status: string;
 78	  name?: string;
 79	  error?: string;
 80	};
 81	
 82	export type StoragePoolBodyProps = {
 83	  cephCluster: CephClusterKind;
 84	  state: StoragePoolState;
 85	  showPoolStatus: boolean;
 86	  dispatch: React.Dispatch<StoragePoolAction | AttachStorageAction>;
 87	  poolType: PoolType;
 88	  existingNames?: string[];
 89	  onPoolTypeChange?: (newPoolType: PoolType) => void;
 90	  disablePoolType?: boolean;
 91	  isUpdate?: boolean;
 92	  prefixName?: string;
 93	  usePrefix?: boolean;
 94	  placeholder?: string;
 95	};
 96	
 97	export const StoragePoolBody: React.FC<StoragePoolBodyProps> = ({
 98	  cephCluster,
 99	  state,
100	  showPoolStatus,
101	  dispatch,
102	  poolType,
103	  existingNames,
104	  onPoolTypeChange,
105	  disablePoolType,
106	  isUpdate,
107	  prefixName,
108	  usePrefix,
109	  placeholder,
110	}) => {
111	  const { t } = useCustomTranslation();
112	
113	  const poolNs = getNamespace(cephCluster);
114	
115	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
116	    useK8sGet<ListKind<StorageClusterKind>>(StorageClusterModel, null, poolNs);
117	
118	  const [isReplicaOpen, setReplicaOpen] = React.useState(false);
119	
120	  const poolNameMaxLength = 253;
121	  const { schema, fieldRequirements } = React.useMemo(() => {
122	    const translationFieldRequirements = [
123	      fieldRequirementsTranslations.maxChars(t, poolNameMaxLength),
124	      fieldRequirementsTranslations.startAndEndName(t),
125	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
126	      fieldRequirementsTranslations.cannotBeUsedBefore(t),
127	    ];
128	
129	    const validationSchema = Yup.object({
130	      newPoolName: Yup.string()
131	        .required()
132	        .max(poolNameMaxLength, translationFieldRequirements[0])
133	        .matches(
134	          validationRegEx.startAndEndsWithAlphanumerics,
135	          translationFieldRequirements[1]
136	        )
137	        .matches(
138	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
139	          translationFieldRequirements[2]
140	        )
141	        .test(
142	          'unique-name',
143	          translationFieldRequirements[3],
144	          (value: string) =>
145	            !existingNames.includes(
146	              usePrefix ? `${prefixName}-${value}` : value
147	            )
148	        ),
149	    });
150	
151	    return {
152	      schema: validationSchema,
153	      fieldRequirements: translationFieldRequirements,
154	    };
155	  }, [prefixName, usePrefix, existingNames, t]);
156	
157	  const resolver = useYupValidationResolver(schema);
158	  const {
159	    formState: { errors },
160	    control,
161	    watch,
162	  } = useForm({
163	    ...formSettings,
164	    resolver,
165	  });
166	
167	  const poolName: string = watch('newPoolName');
168	
169	  React.useEffect(() => {
170	    // Update pool name: set empty on validation error.
171	    const possiblyPrefixedPoolName =
172	      usePrefix && poolName ? `${prefixName}-${poolName}` : poolName;
173	    const payload = errors?.newPoolName ? '' : possiblyPrefixedPoolName;
174	    dispatch({
175	      type: StoragePoolActionType.SET_POOL_NAME,
176	      payload: payload,
177	    });
178	  }, [poolName, dispatch, errors?.newPoolName, prefixName, usePrefix]);
179	
180	  // Failure Domain
181	  React.useEffect(() => {
182	    if (storageClusterLoaded && !storageClusterLoadError)
183	      dispatch({
184	        type: StoragePoolActionType.SET_FAILURE_DOMAIN,
185	        payload: storageCluster?.items[0]?.status?.failureDomain || '',
186	      });
187	  }, [storageCluster, storageClusterLoaded, storageClusterLoadError, dispatch]);
188	
189	  // Check storage cluster is in ready state
190	  const isClusterReady: boolean =
191	    cephCluster?.status?.phase === PoolState.READY;
192	
193	  // Check storage cluster is arbiter
194	  React.useEffect(() => {
195	    const isArbiterCluster: boolean = checkArbiterCluster(
196	      storageCluster?.items[0]
197	    );
198	    dispatch({
199	      type: StoragePoolActionType.SET_POOL_ARBITER,
200	      payload: isArbiterCluster,
201	    });
202	    if (isArbiterCluster) {
203	      dispatch({
204	        type: StoragePoolActionType.SET_POOL_REPLICA_SIZE,
205	        payload: '4',
206	      });
207	    }
208	  }, [
209	    storageCluster,
210	    storageClusterLoaded,
211	    storageClusterLoadError,
212	    state.isArbiterCluster,
213	    dispatch,
214	  ]);
215	
216	  const replicaList: string[] = _.keys(OCS_DEVICE_REPLICA).filter(
217	    (replica: string) =>
218	      (state.isArbiterCluster && replica === '4') ||
219	      (!state.isArbiterCluster && replica !== '4')
220	  );
221	
222	  const replicaDropdownItems = replicaList.map((replica) => {
223	    let warning = '';
224	    if (replica === '2') {
225	      warning = t(
226	        'Data loss may occur, only recommended for small clusters or when backups are available or data loss is acceptable'
227	      );
228	    }
229	    return (
230	      <DropdownItem
231	        key={`replica-${OCS_DEVICE_REPLICA[replica]}`}
232	        component="button"
233	        id={replica}
234	        data-test-id="replica-dropdown-item"
235	        className="ceph-block-pool__dropdown-description"
236	        description={warning}
237	        onClick={(e) =>
238	          dispatch({
239	            type: StoragePoolActionType.SET_POOL_REPLICA_SIZE,
240	            payload: e.currentTarget.id,
241	          })
242	        }
243	      >
244	        {t('{{replica}} Replication', {
245	          replica: OCS_DEVICE_REPLICA[replica],
246	        })}
247	      </DropdownItem>
248	    );
249	  });
250	
251	  const replicaDropdownToggle = (toggleRef: React.Ref<MenuToggleElement>) => (
252	    <MenuToggle
253	      ref={toggleRef}
254	      id="replica-dropdown"
255	      data-test="replica-dropdown"
256	      onClick={() => setReplicaOpen(!isReplicaOpen)}
257	      isExpanded={isReplicaOpen}
258	      icon={<CaretDownIcon />}
259	      isDisabled={state.isArbiterCluster}
260	      isFullWidth
261	    >
262	      {state.replicaSize
263	        ? t('{{replica}} Replication', {
264	            replica: OCS_DEVICE_REPLICA[state.replicaSize],
265	          })
266	        : t('Select replication')}
267	    </MenuToggle>
268	  );
269	
270	  return isClusterReady || !showPoolStatus ? (
271	    <>
272	      <FormGroup label={t('Volume type')} className="pf-v6-u-pt-xl" isRequired>
273	        <div className="pf-v6-u-display-flex pf-v6-u-flex-direction-row ceph-pool__radio-flex">
274	          <Radio
275	            label={t('Filesystem')}
276	            value="filesystem"
277	            id="type-filesystem"
278	            data-test="type-filesystem"
279	            name="volume-type"
280	            className="pf-v6-u-mr-4xl"
281	            isChecked={poolType === PoolType.FILESYSTEM}
282	            isDisabled={disablePoolType && poolType !== PoolType.FILESYSTEM}
283	            onChange={() => {
284	              onPoolTypeChange(PoolType.FILESYSTEM);
285	            }}
286	          />
287	          <Radio
288	            label={t('Block')}
289	            value="block"
290	            id="type-block"
291	            data-test="type-block"
292	            name="volume-type"
293	            isChecked={poolType === PoolType.BLOCK}
294	            isDisabled={disablePoolType && poolType !== PoolType.BLOCK}
295	            onChange={() => {
296	              onPoolTypeChange(PoolType.BLOCK);
297	            }}
298	          />
299	        </div>
300	      </FormGroup>
301	      <TextInputWithFieldRequirements
302	        control={control}
303	        fieldRequirements={fieldRequirements}
304	        defaultValue={state.poolName}
305	        popoverProps={{
306	          headerContent: t('Name requirements'),
307	          footerContent: `${t('Example')}: my-pool`,
308	        }}
309	        formGroupProps={{
310	          label: t('Pool name'),
311	          fieldId: 'pool-name',
312	          className: 'ceph-block-pool-body__input',
313	          isRequired: true,
314	        }}
315	        textInputProps={{
316	          id: 'pool-name',
317	          name: 'newPoolName',
318	          'data-test': 'new-pool-name-textbox',
319	          'aria-describedby': t('pool-name-help'),
320	          placeholder: placeholder || t('my-pool'),
321	          isDisabled: isUpdate,
322	        }}
323	        infoElement={
324	          (usePrefix || poolType === PoolType.FILESYSTEM) && (
325	            <>
326	              <Icon status="info">
327	                <InfoCircleIcon />
328	              </Icon>
329	              <span className="pf-v5-u-disabled-color-100 pf-v6-u-font-size-sm pf-v6-u-ml-sm">
330	                {t(
331	                  'The pool name comprises a prefix followed by the user-provided name.'
332	                )}
333	              </span>
334	            </>
335	          )
336	        }
337	        inputPrefixElement={
338	          (usePrefix || poolType === PoolType.FILESYSTEM) && (
339	            <>
340	              <TextInput
341	                id="pool-prefix"
342	                className="pool-prefix"
343	                value={prefixName}
344	                isDisabled={true}
345	              />
346	              <div className="pf-v6-u-ml-sm pf-v6-u-mr-sm">-</div>
347	            </>
348	          )
349	        }
350	      />
351	      <div className="form-group ceph-block-pool-body__input">
352	        <label
353	          className="control-label co-required"
354	          htmlFor="pool-replica-size"
355	        >
356	          {t('Data protection policy')}
357	        </label>
358	        <Dropdown
359	          className="dropdown--full-width"
360	          isOpen={isReplicaOpen}
361	          onSelect={() => setReplicaOpen(false)}
362	          onOpenChange={(open: boolean) => setReplicaOpen(open)}
363	          toggle={replicaDropdownToggle}
364	          popperProps={{ width: 'trigger' }}
365	        >
366	          <DropdownList>{replicaDropdownItems}</DropdownList>
367	        </Dropdown>
368	      </div>
369	      <div className="form-group ceph-block-pool-body__input">
370	        <label className="control-label" htmlFor="compression-check">
371	          {t('Data compression')}
372	        </label>
373	        <div className="checkbox ceph-block-pool-body__compression">
374	          <input
375	            type="checkbox"
376	            onChange={(event) =>
377	              dispatch({
378	                type: StoragePoolActionType.SET_POOL_COMPRESSED,
379	                payload: event.target.checked,
380	              })
381	            }
382	            checked={state.isCompressed}
383	            id="compression-check"
384	            name="compression-check"
385	            data-test="compression-checkbox"
386	          />
387	          {t(
388	            'Optimize storage efficiency by enabling data compression within replicas.'
389	          )}
390	        </div>
391	      </div>
392	      {state.isCompressed && (
393	        <Alert
394	          className="co-alert ceph-block-pool__alert"
395	          variant="info"
396	          title={t(
397	            'Enabling compression may result in little or no space savings for encrypted or random data. Also, enabling compression may have an impact on I/O performance.'
398	          )}
399	          isInline
400	        />
401	      )}
402	    </>
403	  ) : (
404	    <StoragePoolStatus status={PoolProgress.CLUSTERNOTREADY} />
405	  );
406	};

