192	export const getStoragePoolsFromBlockPools = (
193	  blockPools: StoragePoolKind[]
194	): StoragePool[] => {
195	  return blockPools?.map((pool) => {
196	    pool['type'] = PoolType.BLOCK;
197	    return pool as StoragePool;
198	  });
199	};
200	
201	export const getExistingFsPoolNames = (fsData: CephFilesystemKind): string[] =>
202	  fsData?.spec?.dataPools?.map((dataPool) => {
203	    return dataPool.name ?? POOL_FS_DEFAULT;
204	  });
205	
206	export const getExistingBlockPoolNames = (
207	  blockPools: StoragePoolKind[]
208	): string[] => blockPools?.map((pool) => pool.metadata?.name);
209	
210	export const getFsPoolIndex = (
211	  storageCluster: StorageClusterKind,
212	  poolName: string
213	) =>
214	  storageCluster.spec.managedResources?.cephFilesystems?.additionalDataPools.findIndex(
215	    (additionalPool) => additionalPool.name === poolName
216	  );

